<template>
    <div>
        <div style="margin-bottom: 20px">
            <el-input style="width: 240px" placeholder="请输入分类名称" v-model="params.name"></el-input>
            <el-button style="margin-left: 5px" type="primary" round @click="load"><i class="el-icon-search" ></i>搜索</el-button>
            <el-button style="margin-left: 5px" type="info" round @click="reset"><i class="el-icon-refresh-right" ></i>重置</el-button>
            <el-button style="margin-left: 5px" type="warning" round @click="change"><i class="el-icon-star-off" ></i>添加</el-button>
        </div>
        <el-table :data="tableData" stripe row-key="id" default-expand-all :border="true" size="medium">
<!--            <el-table-column prop="id" label="编号" width="80"></el-table-column>-->
            <el-table-column prop="name" label="名称"></el-table-column>
            <el-table-column prop="remark" label="备注"></el-table-column>
<!--            <el-table-column prop="createtime" label="创建时间"></el-table-column>-->
<!--            <el-table-column prop="updatetime" label="更新时间"></el-table-column>-->
<!--            <el-table-column></el-table-column>-->
            <el-table-column label="操作" >
                <template v-slot="scope">
                    <!--                scope.row就是当前行数据-->
                    <el-button type="success" icon="el-icon-circle-plus"  v-if="!scope.row.pid" @click="handleAdd(scope.row)">添加二级分类</el-button>
                    <el-button style="background-color: darkcyan; color: white" icon="el-icon-edit" @click="$router.push('/editCategory?id=' + scope.row.id)">编辑</el-button>
                    <el-popconfirm
                            style="margin-left: 5px"
                            title="您确定删除吗？"
                            @confirm="del(scope.row.id)"
                    >
                        <el-button type="danger" icon="el-icon-delete" slot="reference">删除</el-button>
                    </el-popconfirm>
                </template>
            </el-table-column>
        </el-table>

        <!--      分页-->
        <div style="margin-top: 20px">
            <el-pagination
                    background
                    :current-page="params.pageNum"
                    :page-size="params.pageSize"
                    layout="prev, pager, next"
                    @current-change="handleCurrentChange"
                    :total="total">
                <!--              tableData.length为当前表格的总个数-->
            </el-pagination>
        </div>
        <el-dialog title="添加二级分类" :visible.sync="dialogFormVisible" width="30%">
            <el-form :model="form" label-width="100px" ref="ruleForm" :rules="rules">
                <el-form-item label="分类名称" :label-width="100" prop="name">
                    <el-input v-model="form.name" autocomplete="off" ></el-input>
                </el-form-item>
                <el-form-item label="分类备注" :label-width="100" prop="remark">
                    <el-input v-model="form.remark" autocomplete="off" ></el-input>
                </el-form-item>

            </el-form>
            <div slot="footer" class="dialog-footer">
                <el-button @click="dialogFormVisible = false">取 消</el-button>
                <el-button type="primary" @click="save">确 定</el-button>
            </div>
        </el-dialog>
    </div>
</template>

<script>
    import request from "@/utils/request";
    import Cookies from 'js-cookie';
    export default {
        name: 'CategoryList',
        data(){
            return{
                admin: Cookies.get('admin') ? JSON.parse(Cookies.get('admin')) : {},
                tableData:[

                ],
                total: 0,
                dialogFormVisible:false,
                form:{

                },
                pid: null,
                params: {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',
                },
                rules:{
                    name: [
                        {required: true, message: '请输入分类名称', trigger: 'blur'},
                        {min: 3, max: 10, message: '长度在 3 到 10 个字符', trigger: 'blur'}
                    ],
                }
            }
        },
        created() {
            this.load()

        },
        methods: {
            
            load() {
                request.get('/category/page',{params: this.params}).then(res =>{
                    if(res.code === '200'){
                        this.tableData = res.data.list
                        this.total = res.data.total

                    }

                })
            },
            reset(){
                this.params = {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',


                }
                this.load()
            },

            handleCurrentChange(pageNum){
                //点击分页按钮触发分页
                this.params.pageNum = pageNum;
                this.load();
            },
            del(id){
                request.delete("/category/delete/"+id).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('删除成功');
                        this.load();
                    //    this.load()用来从新加载数据
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
            },
            handleAdd(row){

                this.pid = row.id;
                this.dialogFormVisible = true;
            },
            save() {
                this.$refs['ruleForm'].validate((valid) => {
                    if(valid){
                        this.form.pid=this.pid;
                        request.post('/category/save',this.form).then(res =>{
                            if(res.code === '200'){
                                this.$notify.success('成功')
                                this.$refs['ruleForm'].resetFields();
                                this.dialogFormVisible = false;
                                this.load();
                            }else{
                                this.$notify.error(res.msg)
                            }
                        })
                    }
                })
            },
            change() {
                this.$router.push('addCategory')
            }

        }


    }
</script>

